npm install --save-dev \
  semantic-release \
  @semantic-release/commit-analyzer \
  @semantic-release/release-notes-generator \
  @semantic-release/changelog \
  @semantic-release/git \
  @semantic-release/github \
  conventional-changelog-conventionalcommits

{
  "branches": ["main"],
  "tagFormat": "v${version}",
  "plugins": [
    ["@semantic-release/commit-analyzer", {
      "preset": "conventionalcommits",
      "releaseRules": [
        { "type": "prompt",  "release": "minor" },
        { "type": "tool",    "release": "minor" },
        { "type": "agent",   "release": "minor" },
        { "type": "eval",    "release": "patch" },
        { "type": "fix",     "release": "patch" },
        { "type": "feat",    "release": "minor" },
        { "type": "chore",   "release": false   },
        { "type": "docs",    "release": false   },
        { "type": "ci",      "release": false   },
        { "breaking": true,  "release": "major" }
      ]
    }],

    ["@semantic-release/release-notes-generator", {
      "preset": "conventionalcommits",
      "presetConfig": {
        "types": [
          { "type": "prompt",  "section": "Prompt Changes",      "hidden": false },
          { "type": "tool",    "section": "Tool Schema Changes",  "hidden": false },
          { "type": "agent",   "section": "Agent Logic Changes",  "hidden": false },
          { "type": "eval",    "section": "Evaluation Suite",     "hidden": false },
          { "type": "fix",     "section": "Bug Fixes",            "hidden": false },
          { "type": "feat",    "section": "New Features",         "hidden": false },
          { "type": "chore",   "section": "Maintenance",          "hidden": true  },
          { "type": "docs",    "section": "Documentation",        "hidden": true  },
          { "type": "ci",      "section": "CI/CD",                "hidden": true  }
        ]
      }
    }],

    "@semantic-release/changelog",

    ["@semantic-release/git", {
      "assets": ["CHANGELOG.md", "package.json"],
      "message": "chore(release): ${nextRelease.version} [skip ci]"
    }],

    ["@semantic-release/github", {
      "successComment": false,
      "failComment": false
    }]
  ]
}

// plugins/eval-ref-changelog-plugin.js
/**
 * semantic-release plugin that appends Eval-ref footers to
 * changelog entries for AI-layer commit types.
 *
 * Add this plugin AFTER @semantic-release/release-notes-generator
 * in .releaserc.json to post-process the generated notes.
 */

const AI_LAYER_TYPES = new Set(['prompt', 'tool', 'agent', 'eval', 'fix']);

function extractEvalRef(rawBody) {
  if (!rawBody) return null;
  const m = rawBody.match(/^Eval-ref:\s*(.+)$/m);
  return m ? m[1].trim() : null;
}

function extractPromptHash(rawBody) {
  if (!rawBody) return null;
  const m = rawBody.match(/^Prompt-hash:\s*(.+)$/m);
  return m ? m[1].trim() : null;
}

/**
 * generateNotes lifecycle hook.
 * Receives the context including commits and the generated notes string,
 * then returns a modified notes string with Eval-ref footers appended.
 */
async function generateNotes(pluginConfig, context) {
  const { commits, nextRelease, logger } = context;
  let notes = nextRelease.notes || '';

  for (const commit of commits) {
    const type = (commit.type || '').toLowerCase();
    if (!AI_LAYER_TYPES.has(type)) continue;

    const evalRef = extractEvalRef(commit.raw?.body);
    const promptHash = extractPromptHash(commit.raw?.body);
    if (!evalRef && !promptHash) continue;

    // The commit subject in the notes looks like:
    //   * **scope:** description ([sha](url))
    // We append the eval ref on the same line in italics.
    const sha8 = commit.hash?.slice(0, 8) ?? '';
    const escapedSubject = commit.subject.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

    const evalNote = evalRef
      ? ` — _eval: [${evalRef}](${evalRef})_`
      : '';
    const hashNote = promptHash
      ? ` — _prompt-hash: \`${promptHash}\`_`
      : '';

    // Replace the first matching line to add eval ref annotation
    notes = notes.replace(
      new RegExp(`(\* .*?${sha8}.*?)$`, 'm'),
      `$1${evalNote}${hashNote}`
    );
  }

  return notes;
}

module.exports = { generateNotes };

{
  "plugins": [
    ["@semantic-release/commit-analyzer", { ... }],
    ["@semantic-release/release-notes-generator", { ... }],
    "./plugins/eval-ref-changelog-plugin.js",
    "@semantic-release/changelog",
    ["@semantic-release/git", { ... }]
  ]
}
